Span<nint> signed = stackalloc nint[] { 1, 2, 3, -4 };
Span<nuint> unsigned = stackalloc nuint[] { 10, 20, 30 };

nint sum = 0;
foreach (var n in signed)
    sum += n;

nuint usum = 0;
foreach (var n in unsigned)
    usum += n;

Console.WriteLine($"Span<nint>  : length={signed.Length}, sum={sum}");
Console.WriteLine($"Span<nuint> : length={unsigned.Length}, sum={usum}");
Console.WriteLine($"sizeof(nint) = {sizeof(nint)} bytes ({sizeof(nint) * 8}-bit platform)");

